Steps:
[GQL-OP search_products]
  query {
    products(
      storeId: "{{STORE_ID}}"
      currencyCode: "USD"
      cultureName: "en-US"
      query: "laptop"
      first: 5
      filter: "category.subtree:@td(VIRTUAL_CATALOG_B2B.id)"
    ) {
      totalCount
      pageInfo { hasNextPage endCursor }
      items {
        id
        code
        name
        slug
        imgSrc
        brandName
        price { actual { amount currency { code } } list { amount } }
        availabilityData { isAvailable isInStock }
      }
    }
  }
[GQL-EXEC search_products]

[GQL-OP discover_product]
  query {
    products(
      storeId: "{{STORE_ID}}"
      currencyCode: "USD"
      cultureName: "en-US"
      first: 1
      filter: "category.subtree:@td(VIRTUAL_CATALOG_B2B.id)"
    ) {
      items { id }
    }
  }
[GQL-EXEC discover_product]
[GQL-CAPTURE discover_product.data.products.items.0.id → PROD_ID]
[GQL-OP get_product]
  query {
    product(
      id: "{{PROD_ID}}"
      storeId: "{{STORE_ID}}"
      currencyCode: "USD"
      cultureName: "en-US"
    ) {
      id
      code
      name
      slug
      outline
      brandName
      imgSrc
      description { content languageCode }
      descriptions { content languageCode }
      price {
        actual { amount currency { code } }
        list { amount }
        sale { amount }
        discountAmount { amount }
        discountPercent
      }
      prices { actual { amount } currency }
      availabilityData { isAvailable isBuyable isInStock availableQuantity }
      images { id url relativeUrl name }
      properties { id name label propertyType propertyValueType }
      keyProperties { id name label }
      seoInfo { semanticUrl }
      category { id level }
    }
  }
[GQL-EXEC get_product]

[GQL-OP get_categories]
  query {
    categories(
      storeId: "{{STORE_ID}}"
      cultureName: "en-US"
      first: 10
    ) {
      totalCount
      items {
        id
        code
        name
        level
        slug
        outline
        childCategories { id name slug }
        seoInfo { id semanticUrl objectType }
      }
    }
  }
[GQL-EXEC get_categories]

[GQL-OP unfiltered_facets]
  query {
    products(
      storeId: "{{STORE_ID}}"
      currencyCode: "USD"
      cultureName: "en-US"
      first: 5
      filter: "category.subtree:@td(VIRTUAL_CATALOG_B2B.id)"
      facet: "Brand"
    ) {
      totalCount
      term_facets {
        name
        label
        facetType
        terms { term label count isSelected }
      }
      range_facets {
        name
        label
        facetType
        ranges { count from to fromStr toStr label isSelected }
      }
      items { id name }
    }
  }
[GQL-EXEC unfiltered_facets]
[GQL-CAPTURE unfiltered_facets.data.products.totalCount → UNFILTERED_COUNT]

[GQL-OP get_variations]
  query {
    product(
      id: "@td(CFG_BIKE.id)"
      storeId: "{{STORE_ID}}"
      currencyCode: "USD"
      cultureName: "en-US"
    ) {
      id
      name
      code
      hasVariations
      isConfigurable
      variations {
        id
        name
        code
        productType
        slug
        availabilityData { isAvailable isBuyable isInStock availableQuantity }
        price { actual { amount currency { code } } list { amount } }
        prices { actual { amount } currency }
        properties { id name label propertyType propertyValueType }
        images { id url }
      }
    }
  }
[GQL-EXEC get_variations]

[GQL-OP list_p]
  query { products(storeId: "{{STORE_ID}}" currencyCode: "USD" first: 1 filter: "category.subtree:@td(VIRTUAL_CATALOG_B2B.id) price.USD:(0.01 TO) inStock_variations:true") { items { id price { actual { amount currency { code } } list { amount } } } } }
[GQL-EXEC list_p]

[GQL-OP range_inclusive]
  query { products(storeId: "{{STORE_ID}}" currencyCode: "USD" first: 3 filter: "category.subtree:@td(VIRTUAL_CATALOG_B2B.id) price.USD:[10 TO 200]") { totalCount items { id price { actual { amount } } } } }
[GQL-EXEC range_inclusive]

[GQL-OP range_open]
  query { products(storeId: "{{STORE_ID}}" currencyCode: "USD" first: 3 filter: "category.subtree:@td(VIRTUAL_CATALOG_B2B.id) price.USD:(0 TO)") { totalCount items { id } } }
[GQL-EXEC range_open]

[GQL-OP range_weight]
  query { products(storeId: "{{STORE_ID}}" currencyCode: "USD" first: 3 filter: "category.subtree:@td(VIRTUAL_CATALOG_B2B.id)") { totalCount items { id } } }
[GQL-EXEC range_weight]

[GQL-OP facet_price]
  query { products(storeId: "{{STORE_ID}}" currencyCode: "USD" first: 1 filter: "category.subtree:@td(VIRTUAL_CATALOG_B2B.id)" facet: "price.USD") { totalCount range_facets { name label ranges { count from to } } } }
[GQL-EXEC facet_price]

[GQL-OP cat_bogus]
  query { category(id: "00000000-0000-0000-0000-000000000000" storeId: "{{STORE_ID}}" cultureName: "en-US") { id name } }
[GQL-EXEC cat_bogus]

[GQL-OP sorted]
  query { products(storeId: "{{STORE_ID}}" currencyCode: "USD" first: 3 sort: "name:asc" filter: "category.subtree:@td(VIRTUAL_CATALOG_B2B.id)") { items { id name } } }
[GQL-EXEC sorted]

[GQL-OP sorted_cats]
  query { categories(storeId: "{{STORE_ID}}" first: 3 sort: "name:asc" cultureName: "en-US") { items { id name level } } }
[GQL-EXEC sorted_cats]

[GQL-OP combo_filter]
  query { products(storeId: "{{STORE_ID}}" currencyCode: "USD" first: 3 filter: "category.subtree:@td(VIRTUAL_CATALOG_B2B.id) price.USD:(10 TO)") { totalCount items { id price { actual { amount } } } } }
[GQL-EXEC combo_filter]

[GQL-OP brand_filter]
  query { products(storeId: "{{STORE_ID}}" currencyCode: "USD" first: 3 filter: "category.subtree:@td(VIRTUAL_CATALOG_B2B.id) Brand:Acme") { totalCount items { id brandName } } }
[GQL-EXEC brand_filter]

[GQL-OP in_stock]
  query { products(storeId: "{{STORE_ID}}" currencyCode: "USD" first: 3 filter: "category.subtree:@td(VIRTUAL_CATALOG_B2B.id) inStock_variations:true") { totalCount items { id availabilityData { isInStock } } } }
[GQL-EXEC in_stock]

[GQL-OP slug_root]
  query { slugInfo(slug: "" storeId: "{{STORE_ID}}") { entityInfo { objectType id } redirectUrl } }
[GQL-EXEC slug_root]

[GQL-OP slug_bogus]
  query { slugInfo(slug: "agent-test-nonexistent-xyz-404" storeId: "{{STORE_ID}}") { entityInfo { objectType id } redirectUrl } }
[GQL-EXEC slug_bogus]

[GQL-OP list_brands]
  query { brands(storeId: "{{STORE_ID}}" first: 5) { totalCount items { id name permalink logoUrl } } }
[GQL-EXEC list_brands]

Assertions:
[ERRORS label=brand_one] errors[] empty
[DATA label=brand_one] data.brand is non-null
[DATA label=brand_one] data.brand.id = {{BRAND_ID}}

